sql:
SELECT dwelling_id, area_id, num_dwellings
FROM dwellings
WHERE year_built > 2000;

SELECT num_pupils
FROM pupil_projections
WHERE year = 2023 AND dwelling_id = 0;

SELECT area_id, num_dwellings, AVG(average_family_size) AS avg_family_size, MAX(year_built) AS latest_year_built
FROM dwellings
GROUP BY area_id;

external_knowledge:
- 'Densely populated areas' refers to areas with a population greater than 20,000; 
- 'Reliable public transportation' refers to a public transportation score greater than 6; 
- 'Significant need for education places' refers to total estimated education places greater than 1000.

sql:
SELECT SUM(num_pupils) AS total_pupils
FROM pupil_projections
WHERE year = 2023;

SELECT required_hours
FROM education_requirements
WHERE age_group = '3-year-olds';

SELECT year, SUM(num_pupils) AS total_pupils, SUM(estimated_education_places) AS total_estimated_education_places
FROM pupil_projections
GROUP BY year;

SELECT num_dwellings
FROM dwellings
WHERE dwelling_id = 1;
